DEFAULT_COLLECTION = "company_kb"
DEFAULT_PERSIST_DIR = "./rag_db"
DEFAULT_MODEL = "gpt-4o-mini"
DEFAULT_EMBED_MODEL = "text-embedding-3-large"


def _sha256(s: str) -> str:
    return hashlib.sha256(s.encode("utf-8", errors="ignore")).hexdigest()


def _now_iso() -> str:
    return time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())


def _read_text_file(path: str) -> str:
    with open(path, "r", encoding="utf-8", errors="ignore") as f:
        return f.read()


def _read_pdf(path: str) -> str:
    if PyPDF2 is None:
        raise RuntimeError("PyPDF2 not installed. pip install pypdf2")
    text_parts = []
    with open(path, "rb") as f:
        reader = PyPDF2.PdfReader(f)
        for page in reader.pages:
            try:
                text_parts.append(page.extract_text() or "")
            except Exception:
                text_parts.append("")
    return "\n".join(text_parts)


def _read_docx(path: str) -> str:
    if docx is None:
        raise RuntimeError("python-docx not installed. pip install python-docx")
    d = docx.Document(path)
    parts = []
    for p in d.paragraphs:
        if p.text:
            parts.append(p.text)
    return "\n".join(parts)


def _read_html(path: str) -> str:
    if BeautifulSoup is None:
        raise RuntimeError("beautifulsoup4 not installed. pip install beautifulsoup4 lxml")
    html = _read_text_file(path)
    soup = BeautifulSoup(html, "lxml")
    for tag in soup(["script", "style", "noscript"]):
        tag.extract()
    text = soup.get_text(separator="\n")
    lines = [ln.strip() for ln in text.splitlines()]
    lines = [ln for ln in lines if ln]
    return "\n".join(lines)


def load_document(path: str) -> Tuple[str, Dict[str, Any]]:
    ext = os.path.splitext(path)[1].lower()
    if ext in [".txt", ".md", ".rst", ".log", ".csv", ".tsv", ".json"]:
        text = _read_text_file(path)
    elif ext in [".pdf"]:
        text = _read_pdf(path)
    elif ext in [".docx"]:
        text = _read_docx(path)
    elif ext in [".html", ".htm"]:
        text = _read_html(path)
    else:
        text = _read_text_file(path)

    meta = {
        "source_path": os.path.abspath(path),
        "source_file": os.path.basename(path),
        "ext": ext,
        "ingested_at": _now_iso(),
    }
    return text, meta


def iter_files(root: str, include_exts: Optional[List[str]] = None, exclude_hidden: bool = True) -> List[str]:
    paths = []
    root = os.path.abspath(root)
    for dirpath, dirnames, filenames in os.walk(root):
        if exclude_hidden:
            dirnames[:] = [d for d in dirnames if not d.startswith(".")]
            filenames = [f for f in filenames if not f.startswith(".")]
        for fn in filenames:
            p = os.path.join(dirpath, fn)
            ext = os.path.splitext(fn)[1].lower()
            if include_exts and ext not in include_exts:
                continue
            paths.append(p)
    return sorted(paths)


def token_len(text: str, model: str = "gpt-4o-mini") -> int:
    if tiktoken is None:
        return max(1, len(text) // 4)
    try:
        enc = tiktoken.encoding_for_model(model)
    except Exception:
        enc = tiktoken.get_encoding("cl100k_base")
    return len(enc.encode(text))


def chunk_text(text: str, chunk_tokens: int = 800, overlap_tokens: int = 150, model: str = "gpt-4o-mini") -> List[str]:
    if not text.strip():
        return []
    if tiktoken is None:
        approx_chars = chunk_tokens * 4
        overlap_chars = overlap_tokens * 4
        chunks = []
        i = 0
        n = len(text)
        while i < n:
            j = min(n, i + approx_chars)
            chunks.append(text[i:j])
            if j >= n:
                break
            i = max(0, j - overlap_chars)
        return [c.strip() for c in chunks if c.strip()]

    try:
        enc = tiktoken.encoding_for_model(model)
    except Exception:
        enc = tiktoken.get_encoding("cl100k_base")

    tokens = enc.encode(text)
    chunks = []
    i = 0
    n = len(tokens)
    while i < n:
        j = min(n, i + chunk_tokens)
        chunk = enc.decode(tokens[i:j])
        chunks.append(chunk)
        if j >= n:
            break
        i = max(0, j - overlap_tokens)
    return [c.strip() for c in chunks if c.strip()]


@dataclass
class RetrievedDoc:
    id: str
    text: str
    metadata: Dict[str, Any]
    score: float


class RAGSystem:
    def __init__(
        self,
        persist_dir: str = DEFAULT_PERSIST_DIR,
        collection_name: str = DEFAULT_COLLECTION,
        openai_api_key: Optional[str] = None,
        llm_model: str = DEFAULT_MODEL,
        embed_model: str = DEFAULT_EMBED_MODEL,
    ):
        if chromadb is None:
            raise RuntimeError("chromadb not installed. pip install chromadb")
        if OpenAI is None:
            raise RuntimeError("openai not installed. pip install openai")

        self.persist_dir = persist_dir
        self.collection_name = collection_name
        self.llm_model = llm_model
        self.embed_model = embed_model

        self.client = OpenAI(api_key=openai_api_key or os.environ.get("OPENAI_API_KEY"))
        if not (openai_api_key or os.environ.get("OPENAI_API_KEY")):
            raise RuntimeError("OPENAI_API_KEY not set (env var) and openai_api_key not provided.")

        self.vdb = chromadb.PersistentClient(
            path=self.persist_dir,
            settings=Settings(anonymized_telemetry=False) if Settings else None,
        )
        self.collection = self.vdb.get_or_create_collection(
            name=self.collection_name,
            metadata={"hnsw:space": "cosine"},
        )

    def embed_texts(self, texts: List[str]) -> List[List[float]]:
        resp = self.client.embeddings.create(
            model=self.embed_model,
            input=texts,
        )
        return [d.embedding for d in resp.data]

    def upsert_documents_from_dir(
        self,
        docs_dir: str,
        include_exts: Optional[List[str]] = None,
        chunk_tokens: int = 800,
        overlap_tokens: int = 150,
        chunk_model_for_tokenizer: Optional[str] = None,
        batch_size: int = 96,
    ) -> Dict[str, Any]:
        docs_dir = os.path.abspath(docs_dir)
        files = iter_files(docs_dir, include_exts=include_exts)
        total_files = len(files)

        added_chunks = 0
        skipped_files = 0
        errors = []

        tokenizer_model = chunk_model_for_tokenizer or self.llm_model

        ids_batch = []
        texts_batch = []
        metas_batch = []

        def flush():
            nonlocal added_chunks, ids_batch, texts_batch, metas_batch
            if not texts_batch:
                return
            embs = self.embed_texts(texts_batch)
            self.collection.upsert(
                ids=ids_batch,
                documents=texts_batch,
                embeddings=embs,
                metadatas=metas_batch,
            )
            added_chunks += len(ids_batch)
            ids_batch, texts_batch, metas_batch = [], [], []

        for fp in files:
            try:
                raw_text, base_meta = load_document(fp)
                raw_text = raw_text.strip()
                if not raw_text:
                    skipped_files += 1
                    continue

                file_hash = _sha256(base_meta["source_path"] + "|" + str(os.path.getmtime(fp)) + "|" + str(os.path.getsize(fp)))
                base_meta["file_hash"] = file_hash

                chunks = chunk_text(raw_text, chunk_tokens=chunk_tokens, overlap_tokens=overlap_tokens, model=tokenizer_model)
                if not chunks:
                    skipped_files += 1
                    continue

                for idx, ch in enumerate(chunks):
                    ch_id = _sha256(file_hash + f"|chunk:{idx}")
                    meta = dict(base_meta)
                    meta.update(
                        {
                            "chunk_index": idx,
                            "chunk_count": len(chunks),
                            "chunk_tokens": token_len(ch, model=tokenizer_model),
                        }
                    )
                    ids_batch.append(ch_id)
                    texts_batch.append(ch)
                    metas_batch.append(meta)

                    if len(texts_batch) >= batch_size:
                        flush()

            except Exception as e:
                errors.append({"file": fp, "error": str(e)})
                continue

        flush()
        return {
            "docs_dir": docs_dir,
            "collection": self.collection_name,
            "persist_dir": self.persist_dir,
            "files_seen": total_files,
            "chunks_added_or_updated": added_chunks,
            "files_skipped": skipped_files,
            "errors": errors,
        }

    def retrieve(self, query: str, k: int = 8) -> List[RetrievedDoc]:
        q_emb = self.embed_texts([query])[0]
        res = self.collection.query(
            query_embeddings=[q_emb],
            n_results=k,
            include=["documents", "metadatas", "distances"],
        )
        ids = res.get("ids", [[]])[0]
        docs = res.get("documents", [[]])[0]
        metas = res.get("metadatas", [[]])[0]
        dists = res.get("distances", [[]])[0]
        out = []
        for i in range(len(ids)):
            dist = float(dists[i]) if dists and i < len(dists) and dists[i] is not None else 0.0
            score = 1.0 - dist
            out.append(RetrievedDoc(id=ids[i], text=docs[i], metadata=metas[i], score=score))
        return out

    def build_prompt(self, query: str, retrieved: List[RetrievedDoc]) -> List[Dict[str, str]]:
        context_blocks = []
        for i, d in enumerate(retrieved, start=1):
            src = d.metadata.get("source_path") or d.metadata.get("source_file") or "unknown"
            chunk_index = d.metadata.get("chunk_index")
            chunk_count = d.metadata.get("chunk_count")
            header = f"[Document {i} | score={d.score:.4f} | source={src}"
            if chunk_index is not None and chunk_count is not None:
                header += f" | chunk={chunk_index+1}/{chunk_count}"
            header += "]"
            context_blocks.append(header + "\n" + d.text.strip())

        context = "\n\n---\n\n".join(context_blocks) if context_blocks else "(no retrieved context)"

        system = (
            "You are an internal company knowledge base assistant. "
            "Use ONLY the provided context to answer the user's question. "
            "If the context does not contain the answer, say you don't know and ask a clarifying question. "
            "Cite sources by Document number(s) like [Document 2]. "
            "Be concise and accurate."
        )

        user = (
            "User question:\n"
            f"{query}\n\n"
            "Retrieved context (use all documents below as context):\n"
            f"{context}"
        )

        return [
            {"role": "system", "content": system},
            {"role": "user", "content": user},
        ]

    def answer(self, query: str, k: int = 8, temperature: float = 0.2) -> Dict[str, Any]:
        retrieved = self.retrieve(query, k=k)
        messages = self.build_prompt(query, retrieved)
        resp = self.client.chat.completions.create(
            model=self.llm_model,
            messages=messages,
            temperature=temperature,
        )
        text = resp.choices[0].message.content
        return {
            "query": query,
            "answer": text,
            "retrieved": [
                {
                    "id": d.id,
                    "score": d.score,
                    "text": d.text,
                    "metadata": d.metadata,
                }
                for d in retrieved
            ],
            "model": self.llm_model,
            "embed_model": self.embed_model,
            "collection": self.collection_name,
            "persist_dir": self.persist_dir,
        }


def main():
    p = argparse.ArgumentParser(description="Simple Python RAG system (ChromaDB + OpenAI).")
    sub = p.add_subparsers(dest="cmd", required=True)

    p_ingest = sub.add_parser("ingest", help="Ingest documents into vector DB.")
    p_ingest.add_argument("--docs-dir", required=True, help="Directory containing company documents.")
    p_ingest.add_argument("--persist-dir", default=DEFAULT_PERSIST_DIR)
    p_ingest.add_argument("--collection", default=DEFAULT_COLLECTION)
    p_ingest.add_argument("--include-exts", default="", help="Comma-separated list like: .txt,.md,.pdf,.docx,.html")
    p_ingest.add_argument("--chunk-tokens", type=int, default=800)
    p_ingest.add_argument("--overlap-tokens", type=int, default=150)
    p_ingest.add_argument("--batch-size", type=int, default=96)
    p_ingest.add_argument("--llm-model", default=DEFAULT_MODEL)
    p_ingest.add_argument("--embed-model", default=DEFAULT_EMBED_MODEL)
    p_ingest.add_argument("--openai-api-key", default=None)

    p_ask = sub.add_parser("ask", help="Ask a question (one-shot).")
    p_ask.add_argument("--query", required=True)
    p_ask.add_argument("--persist-dir", default=DEFAULT_PERSIST_DIR)
    p_ask.add_argument("--collection", default=DEFAULT_COLLECTION)
    p_ask.add_argument("--k", type=int, default=8)
    p_ask.add_argument("--temperature", type=float, default=0.2)
    p_ask.add_argument("--llm-model", default=DEFAULT_MODEL)
    p_ask.add_argument("--embed-model", default=DEFAULT_EMBED_MODEL)
    p_ask.add_argument("--openai-api-key", default=None)
    p_ask.add_argument("--json", action="store_true", help="Output full JSON response (includes retrieved docs).")

    p_chat = sub.add_parser("chat", help="Interactive chat loop.")
    p_chat.add_argument("--persist-dir", default=DEFAULT_PERSIST_DIR)
    p_chat.add_argument("--collection", default=DEFAULT_COLLECTION)
    p_chat.add_argument("--k", type=int, default=8)
    p_chat.add_argument("--temperature", type=float, default=0.2)
    p_chat.add_argument("--llm-model", default=DEFAULT_MODEL)
    p_chat.add_argument("--embed-model", default=DEFAULT_EMBED_MODEL)
    p_chat.add_argument("--openai-api-key", default=None)

    args = p.parse_args()

    if args.cmd == "ingest":
        include_exts = [e.strip().lower() for e in args.include_exts.split(",") if e.strip()] or None
        rag = RAGSystem(
            persist_dir=args.persist_dir,
            collection_name=args.collection,
            openai_api_key=args.openai_api_key,
            llm_model=args.llm_model,
            embed_model=args.embed_model,
        )
        report = rag.upsert_documents_from_dir(
            docs_dir=args.docs_dir,
            include_exts=include_exts,
            chunk_tokens=args.chunk_tokens,
            overlap_tokens=args.overlap_tokens,
            batch_size=args.batch_size,
        )
        print(json.dumps(report, indent=2, ensure_ascii=False))
        return

    if args.cmd == "ask":
        rag = RAGSystem(
            persist_dir=args.persist_dir,
            collection_name=args.collection,
            openai_api_key=args.openai_api_key,
            llm_model=args.llm_model,
            embed_model=args.embed_model,
        )
        out = rag.answer(args.query, k=args.k, temperature=args.temperature)
        if args.json:
            print(json.dumps(out, indent=2, ensure_ascii=False))
        else:
            print(out["answer"])
        return

    if args.cmd == "chat":
        rag = RAGSystem(
            persist_dir=args.persist_dir,
            collection_name=args.collection,
            openai_api_key=args.openai_api_key,
            llm_model=args.llm_model,
            embed_model=args.embed_model,
        )
        print("RAG chat. Type /exit to quit. Type /sources to show last retrieved docs.")
        last = None
        while True:
            try:
                q = input("\nYou> ").strip()
            except (EOFError, KeyboardInterrupt):
                print()
                break
            if not q:
                continue
            if q.lower() in ["/exit", "exit", "quit", "/quit"]:
                break
            if q.lower() == "/sources":
                if not last:
                    print("No previous query.")
                else:
                    for i, d in enumerate(last["retrieved"], start=1):
                        meta = d.get("metadata", {})
                        src = meta.get("source_path") or meta.get("source_file") or "unknown"
                        print(f"[Document {i}] score={d.get('score'):.4f} source={src}")
                continue

            last = rag.answer(q, k=args.k, temperature=args.temperature)
            print("\nAssistant> " + (last["answer"] or "").strip())

        return


if __name__ == "__main__":
    main()